definition.script:
pipeline {
    agent any

    stages {
        stage('Hello') {
            steps {
                echo 'Hello from Jenkins Blue Ocean!'
            }
        }

        stage('Build') {
            steps {
                sh 'mkdir -p build && echo "Build OK"'
                echo 'Build completed!'
            }
        }

        stage('Test') {
            steps {
                echo 'Running tests...'
                echo 'All tests passed!'
            }
        }

        stage('Deploy') {
            steps {
                echo "Deploying build #${env.BUILD_NUMBER}..."
            }
        }
    }

    post {
        always {
            echo "Build #${env.BUILD_NUMBER} - ${currentBuild.result ?: 'SUCCESS'}"
        }
    }
}
